//! Phase 2 Consensus Protocol (Layer 3).
//!
//! Implements the mesh-level consensus logic that sits above the transport layer:
//! - Σ_mesh computation (weighted aggregate of peer sigma_enc values)
//! - CC.SAMN.3 hard re-sync trigger (|dΣ/dK| > τ_Σ)
//! - C5 resonance check at m=10 using 6-digit rational approximations
//! - Anchor verification (weighted majority RCF orbit agreement)
//!
//! Register: CC.SAMN.3, T.SAMN.11, D.SAMN.4, T.SAMN.9.

use num_bigint::BigInt;
use num_rational::BigRational;
use num_traits::{One, Signed, Zero};

use crate::constants::{RESONANCE_M10_COS, MESH_TORSION_PERIOD_M};
use crate::mesh::{sluice_weight, PeerState};

type Q = BigRational;

fn q(n: i64, d: i64) -> Q {
    Q::new(BigInt::from(n), BigInt::from(d))
}

// ─── Σ_mesh: Mesh-Aggregate Sigma ──────────────────────────────────────

/// Compute Σ_mesh: weighted mean of all peer sigma_enc values.
///
/// Σ_mesh = (Σ_i ω_i × σ_i) / (Σ_i ω_i)
///
/// Includes self (weight = 1). Peers with ω = 0 are excluded.
/// This is NOT a field in MeshReceipt — it is computed from the
/// collection of receipts at each K-step.
///
/// Register: CC.SAMN.3 (Σ_mesh for hard re-sync trigger).
pub fn sigma_mesh(
    our_sigma_enc: u32,
    peers: &[PeerState],
    our_k: u64,
    our_rcf: &[u8; 32],
    alpha_p: &Q,
    alpha_gamma: &Q,
    alpha_k: &Q,
    tau_lag: &Q,
    epsilon_sluice: &Q,
) -> Q {
    // Self contribution (weight = 1)
    let our_sigma = Q::new(BigInt::from(our_sigma_enc as i64), BigInt::from(u32::MAX as i64));
    let mut weighted_sum = our_sigma.clone();
    let mut weight_sum = Q::one();

    for peer in peers {
        let w = sluice_weight(
            peer, our_k, our_rcf,
            alpha_p, alpha_gamma, alpha_k, tau_lag, epsilon_sluice,
        );
        if w.is_zero() {
            continue;
        }
        let sigma_j = Q::new(BigInt::from(peer.sigma_enc as i64), BigInt::from(u32::MAX as i64));
        weighted_sum = weighted_sum + &w * &sigma_j;
        weight_sum = weight_sum + &w;
    }

    if weight_sum.is_zero() {
        return Q::zero();
    }
    weighted_sum / weight_sum
}

/// Check CC.SAMN.3: |dΣ/dK| > τ_Σ triggers hard re-sync.
///
/// Returns true if re-sync is needed (sigma drift exceeds threshold).
///
/// Register: CC.SAMN.3.
pub fn sigma_drift_triggers_resync(
    sigma_mesh_new: &Q,
    sigma_mesh_prev: &Q,
    tau_sigma: &Q,
) -> bool {
    let d_sigma = (sigma_mesh_new - sigma_mesh_prev).abs();
    // dΣ/dK for one K-step is just d_sigma
    &d_sigma > tau_sigma
}

// ─── Resonance Check (C5 for Phase 2) ─────────────────────────────────

/// Compute φ_r: normalized chronometric magnitude as phase proxy.
///
/// φ_r = T_k / T_k_max (ratio of current to maximum observed T_k).
/// When T_k_max is zero, returns zero.
///
/// Register: T.SAMN.11.
pub fn phi_r(t_k: &Q, t_k_max: &Q) -> Q {
    if t_k_max.is_zero() {
        return Q::zero();
    }
    t_k / t_k_max
}

/// Check cyclotomic resonance at torsion period m=10.
///
/// ‖φ(R_i) − Re(ζ_m^k)‖ < τ
///
/// Uses 6-digit rational approximations for Re(ζ_10^k).
/// Error < 1e-7, well within ε_sluice = 1e-3.
///
/// Register: T.SAMN.11, D.EXEC.1 C5.
pub fn check_resonance_m10(phi_r_value: &Q, k: u64, tau: &Q) -> bool {
    let phase_idx = (k % MESH_TORSION_PERIOD_M as u64) as usize;
    let (n, d) = RESONANCE_M10_COS[phase_idx % 10];
    let re_zeta = q(n, d);
    let diff = (phi_r_value - &re_zeta).abs();
    &diff < tau
}

/// Full resonance check for a K-step: is this a resonance window,
/// and if so, does the phase align?
///
/// Resonance windows occur at K ≡ 0 (mod m). At non-window steps,
/// resonance always passes (non-blocking).
///
/// Register: T.SAMN.11.
pub fn resonance_at_step(
    k: u64,
    t_k: &Q,
    t_k_max: &Q,
    tau: &Q,
) -> bool {
    if k % MESH_TORSION_PERIOD_M as u64 != 0 {
        return true; // Not a resonance window — non-blocking
    }
    let phi = phi_r(t_k, t_k_max);
    check_resonance_m10(&phi, k, tau)
}

// ─── Anchor Verification ───────────────────────────────────────────────

/// Verify anchor: weighted majority of peers agree on the same RCF orbit class.
///
/// For Phase 2: a receipt majority agreeing on the same rcf_identity is
/// the anchor verification. No full Δ reconstruction needed — the RCF
/// hash IS the orbit representative.
///
/// Passes if the weighted fraction of peers sharing our RCF identity > 0.5.
/// Single-entity (no peers): always passes.
///
/// Register: T.SAMN.9 (anchor verification), D.SAMN.4 (mesh aggregation).
pub fn verify_anchor(
    our_rcf: &[u8; 32],
    peers: &[PeerState],
    our_k: u64,
    alpha_p: &Q,
    alpha_gamma: &Q,
    alpha_k: &Q,
    tau_lag: &Q,
    epsilon_sluice: &Q,
) -> bool {
    if peers.is_empty() {
        return true; // Single-node
    }

    let mut matching_weight = Q::one(); // Self always matches
    let mut total_weight = Q::one();

    for peer in peers {
        let w = sluice_weight(
            peer, our_k, our_rcf,
            alpha_p, alpha_gamma, alpha_k, tau_lag, epsilon_sluice,
        );
        if w.is_zero() {
            continue;
        }
        total_weight = &total_weight + &w;
        if peer.rcf_identity == *our_rcf {
            matching_weight = &matching_weight + &w;
        }
    }

    if total_weight.is_zero() {
        return true; // No weighted peers — vacuously true
    }
    let ratio = matching_weight / total_weight;
    ratio > q(1, 2)
}

