    #[test]
    fn test_sigma_mesh_self_only() {
        // No peers: sigma_mesh = our own sigma
        let result = sigma_mesh(
            1000, &[], 100, &[0; 32],
            &q(1, 1), &q(1, 1), &q(1, 1),
            &q(1, 100), &q(1, 1000),
        );
        let expected = Q::new(BigInt::from(1000i64), BigInt::from(u32::MAX as i64));
        assert_eq!(result, expected, "Sigma mesh with no peers must equal self sigma");
    }

    #[test]
    fn test_sigma_mesh_all_gated_equals_self() {
        // All peers gated (max divergence, stale): only self contributes
        let peers: Vec<PeerState> = (0..5)
            .map(|i| PeerState {
                entity_id: i + 2,
                k_latest: 1,
                rcf_identity: [0xFF; 32],
                t_k_q1616: 0,
                sigma_enc: 99999,
                last_seen_k: 0,
                disc_status: 0,
            })
            .collect();
        let result = sigma_mesh(
            500, &peers, 200, &[0x00; 32],
            &q(1, 1), &q(1, 1), &q(1, 1),
            &q(1, 100), &q(1, 1000),
        );
        let self_sigma = Q::new(BigInt::from(500i64), BigInt::from(u32::MAX as i64));
        assert_eq!(result, self_sigma, "All-gated peers: sigma_mesh = self sigma");
    }

